OS # Linux Syscall Implement # privilege - HardWare Design
CS: code , last two bit, CPL DS: date, last two bit, RPL DPL : destination privilege level check : if CPL &lt; DPL or CPL = DPL; RPL &lt; DPL or RPL = DPL ![[Pasted image 20240608174254.png]] Interupt for Intel x86, INT INTERUPT
// in lib/close.c _syscall1(int,close,int,fd) // in include/unistd.h #define _syscall1(type,name,atype,a) \ type name(atype a) \ { \ long __res; \ __asm__ volatile (&#34;int $0x80&#34; \ : &#34;=a&#34; (__res) \ : &#34;0&#34; (__NR_##name),&#34;b&#34; ((long)(a))); \ if (__res &gt;= 0) \ return (type) __res; \ errno = -__res; \ return -1; \ } // personal open this micro _syscall(int,close,int fd)\ int close(int fd) \ { long_res; _asm_ volatile(&#34;int $0x80&#34; \ : &#34;=fd&#34; (_res) \ : &#34;0&#34; (__NR_##close), &#34;b&#34; ((long)(fd));\ if (__res &gt;= 0) \ return (int) __res; \ errno = __res; \ return -1; \ ) } to find syscall # strace &amp; itrace /proc/[pid]/syscall !
